 1	import React, { FC, useEffect, useState } from 'react';
 2	import { useLocation } from 'react-router-dom-v5-compat';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { useVMIAndPodsForVM } from '@kubevirt-utils/resources/vm';
 6	import { isEmpty } from '@kubevirt-utils/utils/utils';
 7	import { Overview } from '@openshift-console/dynamic-plugin-sdk';
 8	import { ExpandableSection, Title } from '@patternfly/react-core';
 9	import { NavPageComponentProps } from '@virtualmachines/details/utils/types';
10	
11	import MigrationCharts from './MigrationCharts/MigrationCharts';
12	import NetworkCharts from './NetworkCharts/NetworkCharts';
13	import StorageCharts from './StorageCharts/StorageCharts';
14	import TimeRange from './TimeRange/TimeRange';
15	import UtilizationCharts from './UtilizationCharts/UtilizationCharts';
16	import { MetricsTabExpendedSections } from './utils/utils';
17	
18	import './virtual-machine-metrics-tab.scss';
19	
20	const VirtualMachineMetricsTab: FC<NavPageComponentProps> = ({ obj: vm }) => {
21	  const { t } = useKubevirtTranslation();
22	  const location = useLocation();
23	  const { loaded, pods, vmi } = useVMIAndPodsForVM(vm?.metadata?.name, vm?.metadata?.namespace);
24	
25	  const [expended, setExpended] = useState<{ [key in MetricsTabExpendedSections]: boolean }>({
26	    [MetricsTabExpendedSections.migration]: true,
27	    [MetricsTabExpendedSections.network]: true,
28	    [MetricsTabExpendedSections.storage]: true,
29	    [MetricsTabExpendedSections.utilization]: true,
30	  });
31	
32	  const onToggle = (value) => () =>
33	    setExpended((currentOpen) => ({ ...currentOpen, [value]: !currentOpen?.[value] }));
34	
35	  useEffect(() => {
36	    if (!isEmpty(location?.search) && loaded) {
37	      const focusedSectionId = Object.values(MetricsTabExpendedSections).find((focusedSection) =>
38	        location?.search?.includes(focusedSection),
39	      );
40	      const focusedExpandableSection = document.getElementById(focusedSectionId);
41	      focusedExpandableSection.scrollIntoView();
42	    }
43	  }, [location?.search, loaded]);
44	
45	  return (
46	    <div className="virtual-machine-metrics-tab__main">
47	      <Title className="title" headingLevel="h2">
48	        {t('Metrics')}
49	      </Title>
50	      <TimeRange />
51	      <Overview className="virtual-machine-metrics-tab__charts">
52	        <ExpandableSection
53	          id={MetricsTabExpendedSections.utilization}
54	          isExpanded={expended?.[MetricsTabExpendedSections.utilization]}
55	          onToggle={onToggle(MetricsTabExpendedSections.utilization)}
56	          toggleText={t('Utilization')}
57	        >
58	          <UtilizationCharts pods={pods} vmi={vmi} />
59	        </ExpandableSection>
60	
61	        <ExpandableSection
62	          id={MetricsTabExpendedSections.storage}
63	          isExpanded={expended?.[MetricsTabExpendedSections.storage]}
64	          onToggle={onToggle(MetricsTabExpendedSections.storage)}
65	          toggleText={t('Storage')}
66	        >
67	          <StorageCharts vmi={vmi} />
68	        </ExpandableSection>
69	        <ExpandableSection
70	          id={MetricsTabExpendedSections.network}
71	          isExpanded={expended?.[MetricsTabExpendedSections.network]}
72	          onToggle={onToggle(MetricsTabExpendedSections.network)}
73	          toggleText={t('Network')}
74	        >
75	          <NetworkCharts vmi={vmi} />
76	        </ExpandableSection>
77	        <ExpandableSection
78	          id={MetricsTabExpendedSections.migration}
79	          isExpanded={expended?.[MetricsTabExpendedSections.migration]}
80	          onToggle={onToggle(MetricsTabExpendedSections.migration)}
81	          toggleText={t('Migration')}
82	        >
83	          <MigrationCharts vmi={vmi} />
84	        </ExpandableSection>
85	      </Overview>
86	    </div>
87	  );
88	};
89	
90	export default VirtualMachineMetricsTab;

